import { AuthProvider } from "@/components/auth-provider";
import { QuizSettingsProvider } from "@/context/QuizSettingsContext";
import "@/styles/globals.css";
import { Metadata } from "next";

const siteConfig = {
  title: "Community Health Volunteer (CHV)",
  description:
    "Explore engaging modules on youth mental health, covering anxiety, depression, and coping strategies. Empowering young individuals for a healthier future.",
  url: "https://yhealthylife.ukm.my",
};

export const metadata: Metadata = {
  metadataBase: new URL(siteConfig.url),
  title: {
    default: siteConfig.title,
    template: `%s | ${siteConfig.title}`,
  },
  description: siteConfig.description,
  robots: { index: true, follow: true },
  icons: {
    icon: "/favicon/favicon.ico",
    shortcut: "/favicon/favicon-96x96.png",
    apple: "/favicon/apple-touch-icon.png",
  },
  manifest: `/favicon/manifest.json`,
  openGraph: {
    url: siteConfig.url,
    title: siteConfig.title,
    description: siteConfig.description,
    siteName: siteConfig.title,
    images: [`${siteConfig.url}/images/og.png`],
    type: "website",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: siteConfig.title,
    description: siteConfig.description,
    images: [`${siteConfig.url}/images/og.png`],
  },
};

interface RootLayoutProps {
  children: React.ReactNode;
}

export default function RootLayout({ children }: RootLayoutProps) {
  return (
    <html lang="en">
      <meta
        name="apple-mobile-web-app-title"
        content="YHealthy"
      />
      <AuthProvider>
        <QuizSettingsProvider>
          <body>{children}</body>
        </QuizSettingsProvider>
      </AuthProvider>
    </html>
  );
}

interface AuthLayoutProps {
  children: React.ReactNode;
}

export default function AuthLayout({ children }: AuthLayoutProps) {
  return <main>{children}</main>;
}

